package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVFormatTest {

    @Mock
    private Reader mockReader;

    private CSVFormat csvFormat;

    private org.mockito.MockitoSession mocks;

    @BeforeEach
    void setUp() {
        mocks = MockitoAnnotations.openMocks(this);
        csvFormat = CSVFormat.DEFAULT;
    }

    @AfterEach
    void tearDown() throws Exception {
        if (mocks != null) {
            mocks.finishMocking();
        }
    }

    @Test
    void testParseWithValidReader() throws IOException, NoSuchFieldException, IllegalAccessException {
        CSVParser parser = csvFormat.parse(mockReader);
        assertNotNull(parser);

        // Use reflection to access private fields in CSVParser
        Field readerField = CSVParser.class.getDeclaredField("reader");
        readerField.setAccessible(true);
        Object readerValue = readerField.get(parser);
        assertSame(mockReader, readerValue);

        Field formatField = CSVParser.class.getDeclaredField("format");
        formatField.setAccessible(true);
        Object formatValue = formatField.get(parser);
        assertSame(csvFormat, formatValue);
    }

    @Test
    void testParseThrowsIOException() throws IOException {
        assertDoesNotThrow(() -> csvFormat.parse(mockReader));
    }
}
